 1	import { type FC, type MouseEvent, type Ref, useState } from 'react';
 2	import classNames from 'classnames';
 3	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 4	import type { ProviderData } from 'src/modules/Providers/utils/types/ProviderData';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Dropdown, MenuToggle, type MenuToggleElement } from '@patternfly/react-core';
 8	import { EllipsisVIcon } from '@patternfly/react-icons';
 9	
10	import ProviderActionsDropdownItems from './ProviderActionsDropdownItems';
11	
12	import './ProviderActionsDropdown.style.scss';
13	
14	type ProviderActionsDropdownProps = {
15	  data: ProviderData;
16	  isKebab?: boolean;
17	};
18	
19	/**
20	 * ProviderActionsKebabDropdown_ is a helper component that displays a kebab dropdown menu.
21	 * @param {CellProps} props - The properties passed to this component.
22	 * @param {ProviderWithInventory} props.data - The data to be used in ProviderActionsDropdownItems.
23	 * @returns {Element} The rendered dropdown menu component.
24	 */
25	const ProviderActionsDropdown: FC<ProviderActionsDropdownProps> = ({ data, isKebab }) => {
26	  const { t } = useForkliftTranslation();
27	  const [isOpen, setIsOpen] = useState(false);
28	
29	  const onToggleClick = () => {
30	    setIsOpen((open) => !open);
31	  };
32	
33	  const onSelect = (_event: MouseEvent | undefined, _value: string | number | undefined) => {
34	    setIsOpen(false);
35	  };
36	
37	  return (
38	    <ModalHOC>
39	      <Dropdown
40	        className={classNames({ 'forklift-dropdown': !isKebab })}
41	        isOpen={isOpen}
42	        onOpenChange={setIsOpen}
43	        onSelect={onSelect}
44	        toggle={(toggleRef: Ref<MenuToggleElement>) => (
45	          <MenuToggle
46	            ref={toggleRef}
47	            onClick={onToggleClick}
48	            isExpanded={isOpen}
49	            variant={isKebab ? 'plain' : 'default'}
50	          >
51	            {isKebab ? <EllipsisVIcon /> : t('Actions')}
52	          </MenuToggle>
53	        )}
54	        shouldFocusToggleOnSelect
55	        popperProps={{
56	          position: 'right',
57	          width: '200px',
58	        }}
59	      >
60	        <ProviderActionsDropdownItems data={data} />
61	      </Dropdown>
62	    </ModalHOC>
63	  );
64	};
65	
66	export default ProviderActionsDropdown;

